import{a,_ as i,c,b as e,d as l}from"./chunks/error_graph.Cxne47eL.js";import{_ as t,a as p}from"./chunks/skills.BOG3VmgM.js";import{_ as r,o as n,c as d,ag as o}from"./chunks/framework.hRhVUe7m.js";const y=JSON.parse('{"title":"","description":"","frontmatter":{"outline":false,"aside":false},"headers":[],"relativePath":"product.md","filePath":"product.md"}'),_={name:"product.md"};function g(h,s,v,m,u,f){return n(),d("div",null,[...s[0]||(s[0]=[o('<div class="product-header"><div class="product-header__copy"><span class="section-kicker">Product Surface</span><h1>一套产品，覆盖学生学习、记忆沉淀与管理回看</h1><p>MathClaw 不是把大模型嵌进聊天窗口，而是把做题、学习计划、图谱复盘、自动总结和运行管理组织成一个持续运转的产品系统。</p><div class="pill-list"><span>解题工作台</span><span>学习计划</span><span>知识图谱</span><span>错题图谱</span><span>运行状态</span><span>附加输出</span></div></div><div class="product-header__stats"><div class="product-stat"><strong>7</strong><span>核心界面，覆盖学生侧与管理侧</span></div><div class="product-stat"><strong>4</strong><span>连续阶段，从输入到长期回看</span></div><div class="product-stat"><strong>3</strong><span>外部通道，可接入企业微信、QQ、飞书</span></div></div></div><section class="section-block"><div class="section-header"><span class="section-kicker">三条主线</span><h2>把学生体验、结构化记忆和管理运营放在同一个系统里</h2><p>产品页需要清楚回答三个问题：学生怎么用、系统怎么记、管理侧怎么看。MathClaw 的页面设计正是围绕这三条主线展开。</p></div><div class="scenario-grid"><article class="scenario-card"><span class="scenario-card__label">Student Flow</span><h3>学生侧工作流</h3><p>从上传题目到连续追问，学生始终停留在统一工作台，不需要把学习动作拆散到多个入口。</p></article><article class="scenario-card"><span class="scenario-card__label">Memory Layer</span><h3>记忆与复盘</h3><p>学习计划、知识图谱、错题图谱和日周总结共同构成长期学习线索，而不是一次性回答。</p></article><article class="scenario-card"><span class="scenario-card__label">Ops View</span><h3>管理与控制</h3><p>运行状态、心跳和输出风格控制帮助管理者判断系统稳定性，也让产品行为更容易校准。</p></article></div></section><section class="section-block"><div class="section-header"><span class="section-kicker">关键页面</span><h2>每一页都承担明确角色，而不是重复展示同样的信息</h2><p>产品视觉不仅要好看，还要让访问者快速理解页面之间的分工关系。所以这里按场景逐页展示，而不是简单堆一排截图。</p></div><div class="page-showcase"><div class="page-showcase__body"><span class="section-kicker">学生入口</span><h3>解题工作台是整个学习体验的起点</h3><p>学生在这里上传图片和 PDF，查看诊断、讲解、批改和连续追问。它既是交互入口，也是后续记忆沉淀的来源。</p><ul class="page-checklist"><li>统一承接题目输入和追问上下文</li><li>把做题、讲解和批改放在同一界面内</li><li>避免“聊天在一边、资料在另一边”的割裂感</li></ul></div><div class="page-showcase__media"><img src="'+a+'" alt="解题工作台"></div></div><div class="page-showcase page-showcase--reverse"><div class="page-showcase__body"><span class="section-kicker">行动层</span><h3>学习计划把记忆结果转成可执行动作</h3><p>优先复习点、重点纠错方向、明日建议和每周目标都从记忆层抽取出来，让学生知道下一步该做什么，而不是只得到一段回答。</p><ul class="page-checklist"><li>从历史会话提炼优先级和任务顺序</li><li>让学习推进有明确节奏，而不是纯靠即时提问</li><li>把长期跟踪结果转成每天可执行的面板</li></ul></div><div class="page-showcase__media"><img src="'+i+'" alt="学习计划"></div></div><div class="page-showcase"><div class="page-showcase__body"><span class="section-kicker">结构化记忆</span><h3>知识图谱和错题图谱让复盘真正长期化</h3><p>知识图谱突出前置关系和掌握结构，错题图谱聚焦高频错误模式和建议动作。两者一起把“会不会”变成可见的结构状态。</p><ul class="page-checklist"><li>突出知识点之间的前置关系和掌握情况</li><li>沉淀高频错因，方便针对性复盘</li><li>让长期学习不再停留在零散对话记录里</li></ul></div><div class="page-showcase__media"><img src="'+c+'" alt="知识图谱"></div></div><div class="page-showcase page-showcase--reverse"><div class="page-showcase__body"><span class="section-kicker">管理侧</span><h3>运行状态、心跳和附加输出构成控制平面</h3><p>除了学生体验本身，MathClaw 也把系统是否健康、任务是否按节律运行、输出风格如何控制做成了明确页面，方便持续运营。</p><ul class="page-checklist"><li>监控 gateway、console 和自动任务的健康度</li><li>通过心跳和运行状态快速定位问题</li><li>用附加输出规则管理附件回复的风格表达</li></ul></div><div class="page-showcase__media"><img src="'+e+'" alt="运行状态"></div></div></section><section class="section-block"><div class="section-header"><span class="section-kicker">界面矩阵</span><h2>用一组截图把产品表面完整交代清楚</h2><p>对第一次接触 MathClaw 的访问者来说，完整的界面矩阵比单张英雄图更重要，所以这里保留整套页面速览，但用更规整的节奏来展示。</p></div><div class="screen-grid"><figure class="screen-card screen-card--wide"><img src="'+a+'" alt="解题工作台"><figcaption>解题工作台</figcaption></figure><figure class="screen-card"><img src="'+i+'" alt="学习计划"><figcaption>学习计划</figcaption></figure><figure class="screen-card"><img src="'+c+'" alt="知识图谱"><figcaption>知识图谱</figcaption></figure><figure class="screen-card"><img src="'+l+'" alt="错题图谱"><figcaption>错题图谱</figcaption></figure><figure class="screen-card"><img src="'+t+'" alt="心跳与自动任务"><figcaption>心跳与自动任务</figcaption></figure><figure class="screen-card screen-card--wide"><img src="'+p+'" alt="附加输出"><figcaption>附加输出与风格控制</figcaption></figure></div></section><section class="section-block"><div class="section-header"><span class="section-kicker">运作方式</span><h2>页面之间不是并列罗列，而是前后相接</h2><p>从产品展示的角度，最重要的是把“为什么这些页面会一起出现”说清楚。MathClaw 的答案是：它们分别承担输入、运行、记忆和回看四个阶段。</p></div><div class="timeline-grid"><article class="timeline-card"><span class="timeline-card__step">01</span><h3>输入</h3><p>题目、附件和追问都从统一入口进入，产品链路从这里开始建立上下文。</p></article><article class="timeline-card"><span class="timeline-card__step">02</span><h3>运行</h3><p>代理负责解题、讲解、批改和连续追问，并在需要时叠加更合适的输出风格。</p></article><article class="timeline-card"><span class="timeline-card__step">03</span><h3>沉淀</h3><p>学习会话被更新到计划、知识图谱、错题图谱和总结里，形成可持续的学习资产。</p></article><article class="timeline-card"><span class="timeline-card__step">04</span><h3>回看</h3><p>管理侧通过运行状态、心跳和控制页面判断系统是否稳定，并继续优化整体产品节律。</p></article></div></section>',5)])])}const C=r(_,[["render",g]]);export{y as __pageData,C as default};
